def moving_max(nums: list[float], k: int) -> list[float]:
    """Return the maximum value of each contiguous window of length k."""
    if k < 1 or k > len(nums):
        raise ValueError("k must be between 1 and len(nums)")

    result = []
    dq = deque()

    for i, num in enumerate(nums):
        while dq and nums[dq[-1]] <= num:
            dq.pop()
        dq.append(i)
        if dq[0] <= i - k:
            dq.popleft()
        if i >= k - 1:
