def title_case(s: str) -> str:
    """Return a title-cased version of the input string.

    Capitalize the first letter of each word and lowercase the rest,
    except for small words (a, an, and, as, at, but, by, for, in, nor, 
    of, on, or, the, to, vs) which remain lowercase unless they are 
    the first or last word.

    Args:
        s: The input string with words separated by single spaces.

    Returns:
        The title-cased string.

    Raises:
        TypeError: If s is not a string.
    """
    if not isinstance(s, str):
        raise TypeError("Input must be a string")

    small_words = {
        'a', 'an', 'and', 'as', 'at', 'but', 'by', 'for', 
        'in', 'nor', 'of', 'on', 'or', 'the', 'to', 'vs'
    }

    words = s.split(' ')
    result = []

    for i, word in enumerate(words):
        if not word:
            result.append(word)
            continue

        # First and last words are always capitalized
        if i == 0 or i == len(words) - 1:
            result.append(word[0].upper() + word[1:].lower())
        elif word.lower() in small_words:
            result.append(word.lower())
        else:
            result.append(word[0].upper() + word[1:].lower())

    return ' '.join(result)
```

