import heapq
from typing import Dict, List, Any

def topological_sort(graph: Dict[Any, List[Any]]) -> List[Any]:
    """
    Return a deterministic topological ordering of nodes in a directed graph.

    Ties among available nodes are broken by selecting the smallest one.
    Raises ValueError if the graph contains a cycle.
    """
    if not isinstance(graph, dict):
        raise TypeError("graph must be a dictionary")

    in_degree: Dict[Any, int] = {node: 0 for node in graph}
    for successors in graph.values():
        for succ in successors:
            if succ not in in_degree:
                in_degree[succ] = 0
            in_degree[succ] += 1

    heap = [node for node, deg in in_degree.items() if deg == 0]
    heapq.heapify(heap)

    result: List[Any] = []
    while heap:
        node = heapq.heappop(heap)
        result.append(node)

        if node in graph:
            for succ in graph[node]:
                in_degree[succ] -= 1
                if in_degree[succ] == 0:
                    heapq.heappush(heap, succ)

    if len(result) != len(in_degree):
        raise ValueError("Graph contains a cycle")

    return result
