import heapq
from typing import Any, Dict, List, Tuple

def dijkstra(graph: Dict[Any, List[Tuple[Any, float]]], start: Any, end: Any) -> float:
    """Compute the shortest-path distance from `start` to `end` using Dijkstra's algorithm.

    Args:
        graph: Adjacency list mapping nodes to lists of (neighbor, weight) tuples.
        start: Source node.
        end: Destination node.

    Returns:
        Shortest path distance, 0.0 if start == end, or float('inf') if unreachable.

    Raises:
        ValueError: If start/end are not in the graph or any edge weight is negative.
    """
    all_nodes = set(graph.keys())
    for neighbors in graph.values():
        for n, w in neighbors:
            all_nodes.add(n)
            if w < 0:
                raise ValueError("Graph contains negative weights")

    if start not in all_nodes or end not in all_nodes:
        raise ValueError("Start or end node is not in the graph")

    if start == end:
        return 0.0

    dist = {start: 0.0}
    pq = [(0.0, 0, start)]
    counter = 1

    while pq:
        d, _, u = heapq.heappop(pq)

        if d > dist.get(u, float('inf')):
            continue

        if u == end:
            return d

        for v, w in graph.get(u, []):
            new_dist = d + w
            if v not in dist or new_dist < dist[v]:
                dist[v] = new_dist
                heapq.heappush(pq, (new_dist, counter, v))
                counter += 1

    return float('inf')
