    tails = []

    for num in nums:
        # Find the first element in tails that is >= num
        idx = bisect.bisect_left(tails, num)

        if idx == len(tails):
            # num is greater than all elements in tails, extend the longest subsequence
            tails.append(num)
        else:
            # Replace the first element >= num with num to maintain smallest tail
            tails[idx] = num

