def deep_merge(a: dict[Any, Any], b: dict[Any, Any]) -> dict[Any, Any]:
    """Return a new dict merging `a` and `b`.

    For keys present in both with dict values, merge recursively.
    Otherwise, `b`'s value wins. Lists and other types are not merged.
    Neither input nor any nested object is mutated; the result shares
    no mutable objects with `a` or `b`.
