def compress_ranges(nums: list[int]) -> str:
    """
    Compress a list of integers into a string representation where consecutive runs
    of 3 or more are written as 'a-b' and shorter runs as individual values.

    Args:
        nums: A list of integers (any order, possibly with duplicates).

    Returns:
        A string of sorted distinct values joined by commas, with consecutive runs
        of 3+ compressed to 'a-b'.

    Raises:
        TypeError: If nums is not a list or contains non-integer elements.
    """
    if not isinstance(nums, list):
        raise TypeError("Input must be a list")

    for num in nums:
        if not isinstance(num, int):
            raise TypeError(f"All elements must be integers, got {type(num).__name__}")

    if not nums:
        return ""

    # Get sorted distinct values
    unique_sorted = sorted(set(nums))

    if not unique_sorted:
        return ""

    result_parts = []
    start = unique_sorted[0]
    prev = unique_sorted[0]

    for i in range(1, len(unique_sorted)):
        current = unique_sorted[i]
        if current == prev + 1:
            # Continue the run
            prev = current
        else:
            # End of a run
            end = prev
            if end - start >= 2:  # 3 or more consecutive (start, start+1, start+2 => end-start=2)
                result_parts.append(f"{start}-{end}")
            else:
                # Less than 3 consecutive, write individually
                for val in range(start, end + 1):
                    result_parts.append(str(val))
            start = current
            prev = current

    # Handle the last run
    end = prev
    if end - start >= 2:
        result_parts.append(f"{start}-{end}")
    else:
        for val in range(start, end + 1):
            result_parts.append(str(val))

    return ",".join(result_parts)
