            except ValueError:
                raise ValueError(f"Invalid number: {num_str} at position {i}")

            i = j
            continue

        # Operators and parentheses
        if ch in '+-*/()':
            tokens.append(ch)
            i += 1
            continue

        # Invalid character
        raise ValueError(f"Invalid character '{ch}' at position {i}")

    return tokens


class _ExpressionParser:
    """Recursive descent parser for arithmetic expressions."""

    def __init__(self, tokens: list):
        self.tokens = tokens
        self.pos = 0

    def peek(self) -> any:
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self, expected: str = None) -> any:
        token = self.peek()
        if expected is not None and token != expected:
            raise ValueError(f"Expected '{expected}' but got '{token}' at position {self.pos}")
        self.pos += 1
        return token

    def parse_expression(self) -> float:
        """Parse addition and subtraction (lowest precedence)."""
        result = self.parse_term()

        while self.peek() in ('+', '-'):
            op = self.consume()
            right = self.parse_term()
            if op == '+':
                result += right
            else:
                result -= right

        return result

    def parse_term(self) -> float:
        """Parse multiplication and division (higher precedence than +/-)."""
        result = self.parse_unary()

        while self.peek() in ('*', '/'):
            op = self.consume()
            right = self.parse_unary()
            if op == '*':
                result *= right
            else:
                if right == 0:
                    raise ValueError("Division by zero")
                result /= right

        return result

    def parse_unary(self) -> float:
        """Parse unary + and - operators."""
        if self.peek() == '+':
            self.consume('+')
            return self.parse_unary()
        elif self.peek() == '-':
            self.consume('-')
            return -self.parse_unary()

        return self.parse_primary()

    def parse_primary(self) -> float:
        """Parse primary expressions: numbers and parenthesized expressions."""
        token = self.peek()

        if token is None:
            raise ValueError("Unexpected end of expression")

        # Number literal
        if isinstance(token, (int, float)):
            self.consume()
            return float(token)

        # Parenthesized expression
        if token == '(':
            self.consume('(')
            result = self.parse_expression()
            self.consume(')')
            return result

        raise ValueError(f"Unexpected token '{token}' at position {self.pos}")
