import re

_CANONICAL_ROMAN = re.compile(r'^M{0,3}(CM|CD|D?C{0,3})(XC|XL|L?X{0,3})(IX|IV|V?I{0,3})$')

def roman_to_int(s: str) -> int:
    """Convert a canonical Roman numeral string (1-3999) to an integer.

    Raises ValueError for empty strings, invalid characters, non-canonical forms,
    or violations of standard repetition and subtraction rules.
    """
    if not isinstance(s, str):
        raise ValueError("Input must be a string")
    if not s:
        raise ValueError("Roman numeral cannot be empty")
    if not _CANONICAL_ROMAN.fullmatch(s):
        raise ValueError("Invalid or non-canonical Roman numeral")

    roman_map = {'I': 1, 'V': 5, 'X': 10, 'L': 50, 'C': 100, 'D': 500, 'M': 1000}
    total = 0
    prev = 0
    for char in reversed(s):
        curr = roman_map[char]
        if curr < prev:
            total -= curr
        else:
            total += curr
        prev = curr
    return total
